B.Xe=new A.m(B.x,"ATIS kritik u\xe7u\u015f \xf6ncesi bilgileri sunar","ATIS (Otomatik Terminal Bilgi Servisi) g\xfcncel havaliman\u0131 bilgilerini kesintisiz yay\u0131nlar. Pilotlar ATC ile temasa ge\xe7meden \xf6nce g\xfcncel ATIS bilgisini almal\u0131 ve ATIS harfiyle (Alfa, Bravo, Charlie\u2026) ald\u0131klar\u0131n\u0131 teyit etmelidir.\n\nOkuma anlama sorular\u0131 \xe7o\u011funlukla ATIS tarz\u0131 metinler kullanarak belirli bilgileri \xe7\u0131karman\u0131z\u0131 ister.",null,null,null)
