B.Z9=new A.m(B.x,"Havac\u0131l\u0131k raporlar\u0131nda dolayl\u0131 anlat\u0131m","Havac\u0131l\u0131k olay ve kaza raporlar\u0131, m\xfcrettebat \xfcyelerinin veya kontrol\xf6rlerin **s\xf6ylediklerini** veya **d\xfc\u015f\xfcnd\xfcklerini** s\u0131k\xe7a aktar\u0131r. Bu ifadeleri aktarmak i\xe7in kullan\u0131lan dilbilgisi yap\u0131s\u0131na **dolayl\u0131/aktarmal\u0131 anlat\u0131m** denir.\n\nS\u0131nav sorular\u0131 \xe7o\u011funlukla do\u011frudan anlat\u0131m\u0131 dolayl\u0131ya \xe7evirmenizi ya da dolayl\u0131 anlat\u0131m c\xfcmlesini do\u011fru tamamlaman\u0131z\u0131 ister.",null,null,null)
