B.PV=new A.a1('"PAN-PAN PAN-PAN PAN-PAN, Lufthansa 55, medical emergency on board, request priority landing, 2 crew 180 passengers."',"Can tehlikesi yok ama t\u0131bbi acil nedeniyle \xf6ncelikli ini\u015f talep ediliyor.","PAN-PAN \u2026 medical emergency \u2026 priority landing")
B.Ps=new A.a1('"Declaring minimum fuel, request direct routing to reduce flight time."',"Minimum yak\u0131t bildirimi \u2014 acil de\u011fil ama \xf6ncelik istiyor.","minimum fuel \u2026 direct routing")
