B.Y3=new A.m(B.x,"NOTAM nedir?","**NOTAM** (Notice to Air Missions), pilotlar\u0131n haberdar edilmesi gereken havac\u0131l\u0131k bilgilerini i\xe7erir: pist kapan\u0131\u015flar\u0131, VOR ar\u0131zalar\u0131, ge\xe7ici k\u0131s\u0131tlama b\xf6lgeleri ve daha fazlas\u0131.\n\nBu derste ger\xe7ek NOTAM formatlar\u0131n\u0131 \xe7\xf6z\xfcmlemeyi \xf6\u011freneceksin.",null,null,null)
