B.a3h=s(["The beginning of the missed approach","The start of the final approach segment","The runway threshold","The IAF position"],t.s)
B.amJ=new A.r(-271,B.N,641,"The FAF (Final Approach Fix) marks:",B.a3h,1,B.q,null,null,null)
B.abU=s(["Vectors will definitely be given by ATC","The pilot should anticipate radar vectors but fly published procedure if not given","Vectors are not available on this route","The pilot may request vectors"],t.s)
