B.Xp=new A.m(B.x,"CRM neden \xf6nemlidir?","Havac\u0131l\u0131k kazalar\u0131n\u0131n b\xfcy\xfck \xe7o\u011funlu\u011fu (yakla\u015f\u0131k %75) teknik ar\u0131za de\u011fil, **insan fakt\xf6r\xfc** kaynakl\u0131d\u0131r. CRM (Crew Resource Management) e\u011fitimi ve terminolojisi, ICAO ve EASA taraf\u0131ndan zorunlu tutulmakta; s\u0131nav sorular\u0131nda da s\u0131kl\u0131kla yer almaktad\u0131r.",null,null,null)
B.VQ=new A.m(B.v,"\ud83e\udde0 Temel CRM ve \u0130nsan Fakt\xf6r\xfc Terimleri","**SHELL Modeli bile\u015fenleri:**\n\u2022 **S** \u2014 Software (prosed\xfcrler, kontrol listeleri)\n\u2022 **H** \u2014 Hardware (u\xe7ak, ekipman)\n\u2022 **E** \u2014 Environment (\xe7evre ko\u015fullar\u0131)\n\u2022 **L** \u2014 Liveware (\xe7ekirde\u011fi: insan/pilot)\n\u2022 \u0130kinci **L** \u2014 Liveware (di\u011fer insanlar: m\xfcrettebat, ATC)\n\n**TEM (Threat and Error Management):**\n\u2022 **Threat** \u2014 tehdit (d\u0131\u015f kaynakl\u0131 risk)\n\u2022 **Error** \u2014 hata (insan kaynakl\u0131)\n\u2022 **Undesired aircraft state** (UAS) \u2014 istenmeyen u\xe7ak durumu\n\n**CRM kavramlar\u0131:**\n\u2022 **Situational awareness (SA)** \u2192 durum fark\u0131ndal\u0131\u011f\u0131\n\u2022 **Workload management** \u2192 i\u015f y\xfck\xfc y\xf6netimi\n\u2022 **Assertiveness** \u2192 kendini ifade edebilme\n\u2022 **Crew coordination** \u2192 ekip koordinasyonu\n\u2022 **Briefing / Debriefing** \u2192 brifing / debrifing\n\u2022 **Sterile cockpit** \u2192 kritik fazda kokpitte sessizlik\n\u2022 **Go-around decision** \u2192 dalga ge\xe7me karar\u0131",null,null,null)
B.OO=new A.a1('"Loss of situational awareness was identified as a contributing factor in the accident sequence."',"Durum fark\u0131ndal\u0131\u011f\u0131n\u0131n kayb\u0131, kaza seyrinde katk\u0131da bulunan bir fakt\xf6r olarak belirlendi.","Loss of situational awareness \u2026 contributing factor")
B.Or=new A.a1('"The crew failed to complete the checklist due to high workload during the approach phase."',"M\xfcrettebat, yakla\u015fma faz\u0131ndaki y\xfcksek i\u015f y\xfck\xfc nedeniyle kontrol listesini tamamlayamad\u0131.","failed to complete the checklist \u2026 high workload")
B.PN=new A.a1('"Assertiveness training helps crew members speak up when they identify a threat."',"Kendini ifade etme e\u011fitimi, ekip \xfcyelerinin bir tehdit fark ettiklerinde seslerini y\xfckseltmelerine yard\u0131mc\u0131 olur.","Assertiveness \u2026 speak up \u2026 identify a threat")
B.a9D=s([B.OO,B.Or,B.PN],t.l)
