B.Yt=new A.m(B.x,"Kabin ekibi ve acil ileti\u015fim","MAYDAY ve PAN PAN \xe7a\u011fr\u0131lar\u0131 teknik olarak pilotlar taraf\u0131ndan yap\u0131l\u0131r. Ancak kabin ekibinin bu terimlerin anlam\u0131n\u0131, prosed\xfcrler i\xe7indeki rol\xfcn\xfc ve kaptanla ileti\u015fim dilini bilmesi zorunludur.",null,null,null)
B.XZ=new A.m(B.v,"MAYDAY vs PAN PAN",'**MAYDAY** (3 kez tekrar edilir):\n\u2014 Hayati tehlike veya acil yard\u0131m gerektiren durum\n\u2014 Yang\u0131n, dekompresyon, motor ar\u0131zas\u0131, t\u0131bbi kritik durum\n\u2014 Kabin ekibi: kabini tahliye ve brace pozisyonu i\xe7in haz\u0131rlar\n\n**PAN PAN** (3 kez tekrar edilir):\n\u2014 Acil durum de\u011fil, ancak yard\u0131m gerekebilir (urgency)\n\u2014 T\u0131bbi acil durum (hayati tehlike olmayan), yak\u0131t azl\u0131\u011f\u0131\n\u2014 Kabin ekibi: kaptan\u0131 bilgilendirir, normal prosed\xfcr devam eder\n\n**Kabin-Kokpit ileti\u015fimi:**\n"Captain, this is [name] in the cabin. We have a [describe situation]."\n"What are your instructions?"\n"Understood. We will [action]."',null,null,null)
