B.a0h=new A.m(B.x,"Havac\u0131l\u0131k bak\u0131m\u0131nda SMS","**Safety Management System (SMS)**, havac\u0131l\u0131k kurulu\u015flar\u0131n\u0131n g\xfcvenlik risklerini proaktif olarak y\xf6netmesi i\xe7in geli\u015ftirilen sistematik yakla\u015f\u0131md\u0131r. AMT'ler SMS s\xfcre\xe7lerinin aktif kat\u0131l\u0131mc\u0131lar\u0131d\u0131r.",null,null,null)
B.WI=new A.m(B.v,"SMS Terminolojisi",'**Temel kavramlar:**\n\u2022 Hazard \u2014 tehlike (zarar vermek i\xe7in potansiyel mevcut durum)\n\u2022 Risk \u2014 tehlikenin ger\xe7ekle\u015fme olas\u0131l\u0131\u011f\u0131 \xd7 sonucun \u015fiddeti\n\u2022 Safety occurrence \u2014 g\xfcvenlik olay\u0131\n\u2022 Near miss / close call \u2014 ramak kala (hasar olmaks\u0131z\u0131n ger\xe7ekle\u015fen olay)\n\u2022 Root cause analysis \u2014 k\xf6k neden analizi\n\u2022 Corrective action \u2014 d\xfczeltici faaliyet\n\u2022 Preventive action \u2014 \xf6nleyici faaliyet\n\u2022 Just culture \u2014 su\xe7lama yerine \xf6\u011frenmeyi hedefleyen k\xfclt\xfcr\n\u2022 Toolbox talk \u2014 bak\u0131m \xf6ncesi k\u0131sa g\xfcvenlik brifing\n\n**Hazard report ifadesi:**\n"I observed a potential hazard: [description]. Location: [X]. Risk level: [high/medium/low]. Recommended action: [X]."',null,null,null)
B.a6K=s(["Ramak kala olaylar, hasar meydana gelmese bile her zaman raporlanmal\u0131d\u0131r.","Hasar olmayan olaylar rapor edilmek zorunda de\u011fildir.","Ramak kala olaylar yaln\u0131zca ciddi hasara yol a\xe7t\u0131\u011f\u0131nda raporlan\u0131r.","G\xfcvenlik olaylar\u0131 yaln\u0131zca kaza oldu\u011funda kay\u0131t alt\u0131na al\u0131n\u0131r."],t.s)
B.akg=new A.r(-266,B.a5,2136,'Translate to Turkish: "A near miss should always be reported, even if no damage occurred."',B.a6K,0,B.p,null,null,null)
B.a7h=s(["a culture of assigning blame for all safety errors","a culture that encourages reporting by distinguishing between honest mistakes and negligence","a culture where only management decides safety actions","a legal term for fair compensation after accidents"],t.s)
